using System.Diagnostics;

public class Solution
{
    public int ThreeSumMulti(int[] arr, int target)
    {
        // Console.WriteLine($"\nInput: [{string.Join(", ", arr)}], target={target}");
        Dictionary<int, int> count = new();
        foreach (int num in arr)
        {
            count.TryAdd(num, 0);
            count[num]++;
        }
        int[] keys = [.. count.Keys.OrderBy(k => k)];

        long res = 0;
        int mod = 1_000_000_007;

        for (int i = 0; i < keys.Length; i++)
        {
            int a = keys[i];
            // case1 a*3==target
            if (a * 3 == target && count[a] >= 3)
            {
                res += C3(count[a]) % mod;
                Console.WriteLine($"case1: {a}*3=={target}, result+={C3(count[a]) % mod}");
            }

            // case2 a*2+b==target
            int b = target - 2 * a;
            if (b != a && count.ContainsKey(b))
            {
                res += C2(count[a]) * count[b] % mod;
                Console.WriteLine($"case2: {a}*2+{b}=={target}, result+={C2(count[a]) * count[b] % mod}");
            }

            // case3 a+b+c==target
            for (int j = i + 1; j < keys.Length; j++)
            {
                b = keys[j];
                int c = target - a - b;
                if (c > b && count.ContainsKey(c))
                {
                    res += (long)count[a] * count[b] * count[c] % mod;
                    Console.WriteLine($"case3: {a}+{b}+{c}=={target}, result+={count[a] * count[b] * count[c] % mod}");
                }
            }
        }
        return (int)res;
    }
    
    public static long C3(int a)
    {
        return (long)a*(a-1)*(a-2)/6;
    }

    public static long C2(int a)
    {
        return (long)a*(a-1)/2;
    }
}

